class ExamRoom {
public:
    int n;
    vector<int> seats;

    ExamRoom(int n) {
        this->n = n;
    }

    int seat() {
        if (seats.empty()) {
            seats.push_back(0);
            return 0;
        }
        int maxDist = -1;
        int seat = -1;
        if (seats[0] != 0) {
            int dist = seats[0];
            if (dist > maxDist) {
                maxDist = dist;
                seat = 0;
            }
        }
        for (int i = 0; i < seats.size() - 1; i++) {
            int dist = (seats[i + 1] - seats[i]) / 2;
            if (dist > maxDist) {
                maxDist = dist;
                seat = seats[i] + dist;
            }
        }
        if (seats.back() != n - 1) {
            int dist = n - 1 - seats.back();
            if (dist > maxDist) {
                maxDist = dist;
                seat = n - 1;
            }
        }
        seats.push_back(seat);
        sort(seats.begin(), seats.end());
        return seat;
    }

    void leave(int p) {
        auto it = find(seats.begin(), seats.end(), p);
        seats.erase(it);
    }
};
```
